link.script:
window.addEventListener('load', setWindowLoaded);

function getQueryParams() {
  if (window) {
    return window.location.search.length === 0
      ? {}
      : window.location.search
          .substr(1)
          .split('&')
          .map((pairString) => pairString.split('='))
          .reduce((out, pair) => {
            out[pair[0]] = pair[1];
            return out;
          }, {});
  } else {
    return {};
  }
}
const queryParams = getQueryParams();
const marketingSource =
  queryParams['utm_source'] || queryParams['source'] || 'organic';

function setWindowLoaded() {
  windowLoaded = true;
}

function generateRandomString(length = 10) {
  const characters =
    'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
  return Array.from(
    { length },
    () => characters[Math.floor(Math.random() * characters.length)]
  ).join('');
}

stitchIdentifier = sessionStorage.getItem('stitchIdentifier');
if (!stitchIdentifier) {
  stitchIdentifier = marketingSource + '_' + generateRandomString(24);
} else {
  stitchIdentifier =
    marketingSource + '_' + stitchIdentifier.split('_').slice(-1)[0];
}
sessionStorage.setItem('stitchIdentifier', stitchIdentifier);

var xhr = new XMLHttpRequest();
xhr.open(
  'POST',
  'https://api.codingninjas.com/api/v3/partners/partner_analytics_data',
  true
);
xhr.setRequestHeader('Content-Type', 'application/json');
const userAgent = navigator.userAgent.toLowerCase();
xhr.send(
  JSON.stringify({
    event_type: 'initial_load',
    naukri_cvid: stitchIdentifier,
    landing_url:
      queryParams['source_url'] ||
      window.location.host + window.location.pathname,
    data: {
      logical_processors: navigator.hardwareConcurrency,
      device_memory: navigator.deviceMemory,
      network_type: navigator.connection?.effectiveType,
      network_speed: navigator.connection?.downlink,
      isStandalone: (
        navigator.standalone ||
        window.matchMedia('(display-mode: standalone)').matches
      ).toString(),
      inAppView: (
        navigator.standalone ||
        window.matchMedia('(display-mode: standalone)').matches ||
        /wv/.test(userAgent) || // Android WebView
        /iphone|ipod|ipad.*applewebkit(?!.*safari)/.test(userAgent)
      ).toString(), // iOS WebView
      userAgent: userAgent,
      isMobile:
        /android|webos|iphone|ipad|ipod|blackberry|iemobile|opera mini/
          .test(userAgent)
          .toString(),
    },
  })
);
appLoaded = false;
let tick = 1;
const logInterval = setInterval(() => {
  tick += 1;
  if (tick === 15 || window.appLoaded) {
    clearInterval(logInterval);
    return;
  }
  if (tick < 15) {
    const newEventType = `initial_load_${tick}`;
    logPAEvent(newEventType, {});
  }
}, 2000);

const logError = (error) => {
  try {
    const errorMessage = error.message + '\n' + error.stack;
    const eventData = {
      error_message: errorMessage,
      angular_error: false,
    };
    logPAEvent('load_error', eventData);
  } catch (e) {}
};
window.addEventListener('unhandledrejection', (event) => {
  event.preventDefault(); // This will not print the error in the console });

  logError(event.reason);
});
window.addEventListener('error', (event) => {
  event.preventDefault(); // This will not print the error in the console

  logError(event.error);
});

function logPAEvent(eventType, eventData = {}) {
  if (!window.stitchIdentifier) {
    return;
  }
  const xhr = new XMLHttpRequest();
  xhr.open(
    'POST',
    'https://api.codingninjas.com/api/v3/partners/partner_analytics_data',
    true
  );
  xhr.setRequestHeader('Content-Type', 'application/json');
  xhr.send(
    JSON.stringify({
      event_type: eventType,
      naukri_cvid: window.stitchIdentifier,
      landing_url:
        queryParams['source_url'] ||
        window.location.host + window.location.pathname,
      data: eventData,
    })
  );
}

const NON_DELAYED_PATH_ARR = ['/checkout'];
let windowLoaded = false;
window.pushEventsToQueue = true;
window.gtmEventQueue = [];
window.gtmEcommerceQueue = [];
window.gtmScriptInit = false;
document.addEventListener('DOMContentLoaded', () => {
  const nonDelayedPath = !!location.pathname.match(
    NON_DELAYED_PATH_ARR.join('|')
  );
  let delayTime = nonDelayedPath ? 0 : 7000;
  if (!nonDelayedPath && window.navigator.userAgentData) {
    delayTime = window.navigator.userAgentData.mobile ? 10000 : 5000;
  }
  if (window.gtmEventQueue === undefined) {
    window.gtmEventQueue = [];
  }
  if (window.gtmEcommerceQueue === undefined) {
    window.gtmEcommerceQueue = [];
  }
  document.addEventListener('DOMContentLoaded', () => {
    setTimeout(initGTM, delayTime);
  });
  document.addEventListener('scroll', initGTM);
  document.addEventListener('mousemove', initGTM);
  document.addEventListener('touchstart', initGTM);
  function initGTM() {
    if (window.gtmScriptInit) {
      return false;
    }
    const event = new Event('gtm_script_loaded');
    window.gtmScriptInit = true; // flag to ensure script does not get added to DOM more than once.
    (function (w, d, s, l, i) {
      w[l] = w[l] || [];
      w[l].push({ 'gtm.start': new Date().getTime(), event: 'gtm.js' });
      var f = d.getElementsByTagName(s)[0],
        j = d.createElement(s),
        dl = l != 'dataLayer' ? '&l=' + l : '';
      j.async = true;
      j.src =
        'https://www.googletagmanager.com/gtm.js?id=' +
        i +
        dl +
        '&gtm_auth=2Obs6MKGpBvVcCJFBFgP7A&gtm_preview=env-325&gtm_cookies_win=x';
      f.parentNode.insertBefore(j, f);
      j.onload = () => {
        window.dispatchEvent(event);
        window.gtmScriptInit = true; // flag to ensure script does not get added to DOM more than once
        window.pushEventsToQueue = false;
      };
    })(window, document, 'script', 'dataLayer', 'GTM-NSRR859');
  }
});

