img.script:
function handleLoader(loaderDiv) {
  const normalLoader = `






    `;

  const iitgLoader = `




  `;

  if (
    window.location.href.includes(
      '/careercamp/pg-certification-data-analytics'
    ) ||
    window.location.href.includes('/data-analytics-iitg-certification')
  ) {
    loaderDiv.innerHTML = iitgLoader;
  } else {
    loaderDiv.innerHTML = normalLoader;
  }
}

const loaderDiv = document.getElementById('loader');
if (loaderDiv) {
  handleLoader(loaderDiv);
}

if (document) {
  const inputToStorageKey = [
    { 'user-detail-name': 'userName' },
    { 'jb-da-webinar-email-input': 'userEmail' },
    { 'jb-da-webinar-phone-input': 'userPhoneNumber' },
    { 'jb-fsd-webinar-email-input': 'userEmail' },
    { 'jb-fsd-webinar-phone-input': 'userPhoneNumber' },
  ];

  inputToStorageKey.forEach((mapping) => {
    const [inputId, storageKey] = Object.entries(mapping)[0];
    const inputElement = document.getElementById(inputId);

    if (inputElement) {
      // Set the input value from sessionStorage if available
      const storedValue = sessionStorage.getItem(storageKey);
      if (storedValue !== null) {
        inputElement.value = storedValue;
      }

      // Add event listener to update sessionStorage on input
      inputElement.addEventListener('input', function () {
        sessionStorage.setItem(storageKey, this.value);
      });
    }
  });
}
